         /// A CUDA event resource.
-        pub const CUDA_EVENT: u32 = NVTX_RESOURCE_TYPE_CUDA_EVENT;
+        pub const CUDA_EVENT: u32 = super::resource_type_u32(NVTX_RESOURCE_TYPE_CUDA_EVENT);
     }
     #[cfg(feature = "cuda")]
     pub use cuda::*;
@@ -132,11 +150,11 @@ pub mod resource_type {
